var o=new Intl.NumberFormat("nl-NL",{minimumFractionDigits:2,maximumFractionDigits:2});function a(t){return`\u20AC ${o.format(t)}`}function s(t){let n=t.split("-");if(n.length!==3)return t;let[r,e,i]=n;return`${i}-${e}-${r}`}function m(t){let[n,r,e]=t.split("-").map(Number);return new Date(e,r-1,n)}function u(t,n){return[...new Set(t.map(n))].sort((r,e)=>r.localeCompare(e))}export{a,s as b,m as c,u as d};
